module MulAccVerifier (
  input               reset,
  input               clk
);
  reg [2:0] counter;
  reg [31:0] mem [0:3];

  /* Init handling */
  always @(posedge clk) begin
    if($initstate()) begin
      assume(reset);
    end
  end
  initial begin
    $readmemb("mem_reset.bin",mem);
  end

  always @(posedge clk) begin
    if(!reset) begin
      if(counter == 3'b111) begin
        /* Fail on purpose for debugging */
        assert(1'b0);
        assert((mem[counter[1:0]] == 32'hBBBB));
      end
    end
  end

  always @(posedge clk) begin
    if(reset) begin
      counter <= 3'b000;
    end else begin
      counter <= (counter + 3'd001);
      mem[counter[1:0]] <= 32'hBBBB;
    end
  end
endmodule

int i;
      for (i = 0; i < 4; i = i + 1) begin
        if (counter[1:0] == i) begin
          mem[i] <= 32'hBBBB;
        end
      end
